-- Ghana Tertiary UniConnect Dataset - part 4
-- Run parts sequentially in Supabase SQL Editor.

update public.faculties set source_id = coalesce(source_id, 'akrokerri_coe_education') where source_id = 'akrokerri_coe_education' or (name = 'Education' and university_id = (select id from public.universities where source_id = 'akrokerri_coe'));
insert into public.faculties (source_id, university_id, name) select 'akrokerri_coe_basic_education', u.id, 'Basic Education' from public.universities u where u.source_id = 'akrokerri_coe' and not exists (select 1 from public.faculties where source_id = 'akrokerri_coe_basic_education' or (university_id = u.id and name = 'Basic Education'));
